70: 	if err != nil {
71: 		return err
72: 	}
73: 	defer sk.Close()
74: 
75: 	if pnc.stored {
76: 		if err := sk.Set(pnc.namespaceID, cniKey, pnc); err != nil {
77: 			return err
78: 		}
79: 	} else {
80: 		if err := sk.Create(pnc.namespaceID, cniKey, pnc); err != nil {
81: 			return err
82: 		}
83: 	}
84: 	pnc.stored = true
85: 	return nil
86: }
