90: func (pnc *PersistedNamespaceConfig) Remove() error {
91: 	if pnc.stored {
92: 		sk, err := regstate.Open(cniRoot, false)
93: 		if err != nil {
94: 			if regstate.IsNotFoundError(err) {
95: 				pnc.stored = false
